INSERT INTO "UXInstrument"(instrument_id,name,version,description,reference_url) VALUES('a129efda-dd02-4992-aa0e-c00b1314ea26','BANGS','1.0','Basic Needs in Games Scale','https://doi.org/10.1016/j.chb.2020.106360');
INSERT INTO "Item"(item_id,instrument_id,item_number,subscale,text) VALUES
  ('e39fce00-dc34-49cf-a2cd-899a1d1a507f','a129efda-dd02-4992-aa0e-c00b1314ea26',1,'autonomy','Me sentí libre de jugar el juego como yo quería'),
  ('21856bac-0d3c-42d0-95bb-205fa9a349c2','a129efda-dd02-4992-aa0e-c00b1314ea26',2,'autonomy','Sentí que mis elecciones en el juego reflejaban mis propios deseos e intereses'),
  ('6a04ef6d-84d1-4c63-8284-0814a5776207','a129efda-dd02-4992-aa0e-c00b1314ea26',3,'autonomy','Tuve la oportunidad de tomar decisiones significativas sobre cómo progresar'),
  ('63ed4d27-995f-4032-8322-8d016ffb055f','a129efda-dd02-4992-aa0e-c00b1314ea26',4,'autonomy','A menudo me sentí obligado a jugar de cierta manera'),
  ('43295a2f-0c6e-47a3-acae-3852b8dcf974','a129efda-dd02-4992-aa0e-c00b1314ea26',5,'autonomy','Sentí que el juego limitaba mi libertad innecesariamente'),
  ('f7f58061-1576-431d-82e4-9a091ab19c9b','a129efda-dd02-4992-aa0e-c00b1314ea26',6,'autonomy','A menudo me encontré haciendo cosas que realmente no quería hacer en el juego'),
  ('09aa1a8e-f537-4716-9859-bf642cb86bab','a129efda-dd02-4992-aa0e-c00b1314ea26',7,'competence','Sentí que podía dominar los retos de este juego'),
  ('0a3e2e8f-ad5a-47e5-830c-e9d7bd42fbfb','a129efda-dd02-4992-aa0e-c00b1314ea26',8,'competence','Sentí una sensación de logro al jugar'),
  ('a7be0d71-478a-445a-961e-ad629e7678fb','a129efda-dd02-4992-aa0e-c00b1314ea26',9,'competence','Sentí que era capaz de superar los obstáculos del juego'),
  ('9491357d-545c-4de7-8000-c518bb01f0fc','a129efda-dd02-4992-aa0e-c00b1314ea26',10,'competence','Sentí que el juego era demasiado difícil y me frustraba'),
  ('0b67d4fc-b71f-46fc-a0a1-b32530a955db','a129efda-dd02-4992-aa0e-c00b1314ea26',11,'competence','A menudo me sentí incompetente o incapaz de jugar bien'),
  ('71c14d60-9295-4214-8b79-8dca84bb63bb','a129efda-dd02-4992-aa0e-c00b1314ea26',12,'competence','Sentí que mis esfuerzos eran inútiles para lograr mis objetivos'),
  ('daf6b337-845a-49e6-a27f-cc8e3fed4d7e','a129efda-dd02-4992-aa0e-c00b1314ea26',13,'relatedness','Sentí una fuerte conexión con otros jugadores o personajes'),
  ('6f408418-1658-4a91-8ea0-54fe124aa286','a129efda-dd02-4992-aa0e-c00b1314ea26',14,'relatedness','Sentí que me importaban y me valoraban dentro del entorno del juego'),
  ('c9986ec2-e385-43ac-96d9-700bc5595e49','a129efda-dd02-4992-aa0e-c00b1314ea26',15,'relatedness','Sentí que formaba parte de una comunidad o equipo'),
  ('85aa4b30-2533-461b-8bc1-e349b9bf2c1b','a129efda-dd02-4992-aa0e-c00b1314ea26',16,'relatedness','Sentí que los demás jugadores/personajes me ignoraban o excluían'),
  ('9e4cce5f-130e-440e-8c3f-cfe084480a61','a129efda-dd02-4992-aa0e-c00b1314ea26',17,'relatedness','Sentí una desconexión emocional con el mundo del juego y sus personajes'),
  ('7e107b59-2728-4e48-927f-67ddddd171f5','a129efda-dd02-4992-aa0e-c00b1314ea26',18,'relatedness','Sentí que mis interacciones con otros jugadores o personajes eran superficiales o frustrantes');
