--  DoomDB — Seed completo

BEGIN; -- 1. USER

CREATE TABLE IF NOT EXISTS "User" (
    user_id         UUID         PRIMARY KEY DEFAULT gen_random_uuid(),
    username        VARCHAR(100) NOT NULL,
    email           VARCHAR(255) NOT NULL UNIQUE,
    birth_date      DATE,
    country         VARCHAR(100),
    gender          VARCHAR(50),
    consent_given   BOOLEAN      NOT NULL DEFAULT FALSE
);

-- ============================================================
COMMIT;
BEGIN; -- 2. PLAYER
-- 2. PLAYER
-- ============================================================
CREATE TABLE IF NOT EXISTS "Player" (
    player_id   UUID        PRIMARY KEY DEFAULT gen_random_uuid(),
    user_id     UUID        NOT NULL REFERENCES "User"(user_id) ON DELETE CASCADE,
    skill_level VARCHAR(50),
    created_at  TIMESTAMP   NOT NULL DEFAULT NOW()
);

-- ============================================================
COMMIT;

BEGIN; -- 3. MAP
-- 3. MAP
-- ============================================================
CREATE TABLE IF NOT EXISTS "Map" (
    map_id      UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    episode     INT  NOT NULL,
    map_number  INT  NOT NULL,
    map_name    VARCHAR(100),
    UNIQUE (episode, map_number)
);

-- ============================================================
COMMIT;

BEGIN; -- 4. SECTORS
-- 4. SECTOR
-- ============================================================
CREATE TABLE IF NOT EXISTS "Sector" (
    sector_id     UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    map_id        UUID NOT NULL REFERENCES "Map"(map_id) ON DELETE CASCADE,
    sector_number INT  NOT NULL,
    UNIQUE (map_id, sector_number)
);

-- ============================================================
COMMIT;

BEGIN; -- 5. GAME
-- 5. GAME
-- ============================================================
CREATE TABLE IF NOT EXISTS "Game" (
    game_id     UUID         PRIMARY KEY DEFAULT gen_random_uuid(),
    player_id   UUID         NOT NULL REFERENCES "Player"(player_id) ON DELETE CASCADE,
    wad_file    VARCHAR(255) NOT NULL,
    start_game  TIMESTAMP    NOT NULL DEFAULT NOW(),
    end_time    TIMESTAMP,
    episode     INT          NOT NULL,
    map         INT          NOT NULL,
    difficulty  VARCHAR(50)  NOT NULL
);

-- ============================================================
COMMIT;

BEGIN; -- 6. TELEMETRY EVENTS
-- 6. TELEMETRY EVENT
-- ============================================================
CREATE TABLE IF NOT EXISTS "TelemetryEvent" (
    event_id    UUID        PRIMARY KEY DEFAULT gen_random_uuid(),
    game_id     UUID        NOT NULL REFERENCES "Game"(game_id) ON DELETE CASCADE,
    sector_id   UUID        REFERENCES "Sector"(sector_id) ON DELETE SET NULL,
    tic         INT         NOT NULL,
    pos_x       FLOAT       NOT NULL,
    pos_y       FLOAT       NOT NULL,
    pos_z       FLOAT       NOT NULL,
    angle       FLOAT       NOT NULL,
    health      INT,
    armor       INT,
    ammo        INT,
    event_type  VARCHAR(50) NOT NULL,
    ts          TIMESTAMP   NOT NULL DEFAULT NOW()
);
COMMIT;
-- ============================================================
-- 7. UX INSTRUMENT
-- ============================================================
BEGIN;
CREATE TABLE IF NOT EXISTS "UXInstrument" (
    instrument_id   UUID         PRIMARY KEY DEFAULT gen_random_uuid(),
    name            VARCHAR(100) NOT NULL,
    version         VARCHAR(50),
    description     TEXT,
    reference_url   TEXT
);
COMMIT;
-- ============================================================
-- 8. ITEM
-- ============================================================
BEGIN;
CREATE TABLE IF NOT EXISTS "Item" (
    item_id         UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    instrument_id   UUID NOT NULL REFERENCES "UXInstrument"(instrument_id) ON DELETE CASCADE,
    item_number     INT  NOT NULL,
    subscale        VARCHAR(100),
    text            TEXT NOT NULL,
    UNIQUE (instrument_id, item_number)
);
COMMIT;
-- ============================================================
-- 9. RESPONSE
-- ============================================================
BEGIN;
CREATE TABLE IF NOT EXISTS "Response" (
    response_id     UUID      PRIMARY KEY DEFAULT gen_random_uuid(),
    user_id         UUID      NOT NULL REFERENCES "User"(user_id) ON DELETE CASCADE,
    instrument_id   UUID      NOT NULL REFERENCES "UXInstrument"(instrument_id),
    completed_at    TIMESTAMP NOT NULL DEFAULT NOW()
);
COMMIT;
-- ============================================================
-- 10. RESPONSE ITEM
-- ============================================================
BEGIN;
CREATE TABLE IF NOT EXISTS "ResponseItem" (
    response_item_id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    response_id      UUID NOT NULL REFERENCES "Response"(response_id) ON DELETE CASCADE,
    item_id          UUID NOT NULL REFERENCES "Item"(item_id),
    score            INT  NOT NULL CHECK (score BETWEEN 1 AND 7),
    UNIQUE (response_id, item_id)
);
COMMIT;
-- ============================================================
-- ÍNDICES  (performance)
-- ============================================================
CREATE INDEX idx_player_user         ON "Player"(user_id);
CREATE INDEX idx_game_player         ON "Game"(player_id);
CREATE INDEX idx_telemetry_game      ON "TelemetryEvent"(game_id);
CREATE INDEX idx_telemetry_sector    ON "TelemetryEvent"(sector_id);
CREATE INDEX idx_sector_map          ON "Sector"(map_id);
CREATE INDEX idx_item_instrument     ON "Item"(instrument_id);
CREATE INDEX idx_response_user       ON "Response"(user_id);
CREATE INDEX idx_response_instrument ON "Response"(instrument_id);
CREATE INDEX idx_respitem_response   ON "ResponseItem"(response_id);
CREATE INDEX idx_respitem_item       ON "ResponseItem"(item_id);
