WITH numbered AS
(
    SELECT
        game_id,
        ROW_NUMBER() OVER (ORDER BY game_id) AS rn
    FROM "Game"
)
UPDATE "Game" g
SET
    episode =
    CASE
        WHEN n.rn <= 6 THEN 1
        WHEN n.rn <= 9 THEN 1
        WHEN n.rn <= 10 THEN 1
        WHEN n.rn <= 11 THEN 2
        ELSE 3
    END,
    map =
    CASE
        WHEN n.rn <= 6 THEN 1
        WHEN n.rn <= 9 THEN 2
        WHEN n.rn <= 10 THEN 3
        WHEN n.rn <= 11 THEN 1
        ELSE 1
    END
FROM numbered n
WHERE g.game_id = n.game_id;

SELECT
    episode,
    map,
    COUNT(*)
FROM "Game"
GROUP BY episode,map
ORDER BY episode,map;


WITH events AS
(
    SELECT
        event_id,
        ROW_NUMBER() OVER (ORDER BY event_id) AS rn
    FROM "TelemetryEvent"
),
games AS
(
    SELECT
        game_id,
        ROW_NUMBER() OVER (ORDER BY game_id) AS rn
    FROM "Game"
)
UPDATE "TelemetryEvent" te
SET game_id = g.game_id
FROM events e
JOIN games g
ON ((e.rn - 1) % 12) + 1 = g.rn
WHERE te.event_id = e.event_id;


SELECT
    game_id,
    COUNT(*)
FROM "TelemetryEvent"
GROUP BY game_id
ORDER BY COUNT(*) DESC;

SELECT COUNT(*)
FROM "Sector";


WITH maps AS
(
    SELECT
        map_id,
        ROW_NUMBER() OVER
        (
            ORDER BY episode,map_number
        ) AS rn
    FROM "Map"
),
sectors AS
(
    SELECT
        sector_id,
        ROW_NUMBER() OVER
        (
            ORDER BY sector_id
        ) AS rn
    FROM "Sector"
)
UPDATE "Sector" s
SET map_id = m.map_id
FROM sectors sec
JOIN maps m
ON ((sec.rn - 1) % 5) + 1 = m.rn
WHERE s.sector_id = sec.sector_id;


SELECT
    m.episode,
    m.map_number,
    COUNT(*)
FROM "Sector" s
JOIN "Map" m
ON s.map_id = m.map_id
GROUP BY m.episode,m.map_number
ORDER BY m.episode,m.map_number;
