-- ENTREGA 3: Queries analíticos, vistas, índices y mecanismo para recrear el esquema.

-- Queries escogidos: 1, 2, 4, 5, 7, 8

-- QUERY 1: Duración promedio de sesiones por mapa

SELECT
    m.map_name,
    m.episode,
    m.map_number,
    COUNT(DISTINCT te.game_id)                          AS total_sesiones,
    ROUND(AVG((max_tic - min_tic) / 35.0), 2)          AS duracion_promedio_seg,
    ROUND(AVG((max_tic - min_tic) / 35.0 / 60.0), 2)   AS duracion_promedio_min
FROM "Map" m
JOIN "Game" g     ON g.episode = m.episode AND g.map = m.map_number
JOIN (
    SELECT game_id,
           MAX(tic) AS max_tic,
           MIN(tic) AS min_tic
    FROM "TelemetryEvent"
    GROUP BY game_id
) te ON te.game_id = g.game_id
GROUP BY m.map_name, m.episode, m.map_number
ORDER BY m.episode, m.map_number;

--QUERY 2: Jugadores con el mayor promedio de proximidad

WITH posiciones_por_tic AS (
    SELECT 
        g.episode,
        g.map                                 AS map_number,
        te.game_id,
        g.player_id,
        te.tic,
        te.pos_x,
        te.pos_y,
        te.pos_z
    FROM "TelemetryEvent" te
    JOIN "Game" g ON g.game_id = te.game_id
),
parejas_proximidad AS (
    SELECT 
        p1.episode,
        p1.map_number,
        p1.tic,
        p1.player_id                          AS player_1,
        p2.player_id                          AS player_2,
        SQRT(
            POWER(p1.pos_x - p2.pos_x, 2) + 
            POWER(p1.pos_y - p2.pos_y, 2) + 
            POWER(p1.pos_z - p2.pos_z, 2)
        )                                     AS distancia
    FROM posiciones_por_tic p1
    JOIN posiciones_por_tic p2 ON p1.episode = p2.episode 
                               AND p1.map_number = p2.map_number
                               AND p1.tic = p2.tic
                               AND p1.player_id < p2.player_id
)
SELECT 
    u1.username                               AS jugador_1,
    u2.username                               AS jugador_2,
    ROUND(AVG(pp.distancia)::NUMERIC, 4)      AS distancia_promedio,
    COUNT(*)                                  AS tics_cercanos
FROM parejas_proximidad pp
JOIN "Player" pl1 ON pl1.player_id = pp.player_1
JOIN "User"   u1  ON u1.user_id    = pl1.user_id
JOIN "Player" pl2 ON pl2.player_id = pp.player_2
JOIN "User"   u2  ON u2.user_id    = pl2.user_id
WHERE pp.distancia <= 5.0
GROUP BY u1.user_id, u1.username, u2.user_id, u2.username
ORDER BY distancia_promedio ASC, tics_cercanos DESC;


-- QUERY 4: Respuestas UX de jugadores con duración de trayectoria por encima del promedio

WITH duracion_por_juego AS (
    SELECT
        g.player_id,
        te.game_id,
        (MAX(te.tic) - MIN(te.tic)) / 35.0 AS duracion_seg
    FROM "TelemetryEvent" te
    JOIN "Game" g ON g.game_id = te.game_id
    GROUP BY g.player_id, te.game_id
),
promedio_global AS (
    -- El promedio de duración de absolutamente todas las trayectorias del sistema
    SELECT AVG(duracion_seg) AS avg_global FROM duracion_por_juego
),
duracion_promedio_por_jugador AS (
    -- Calculamos el promedio real de cada jugador sumando/promediando sus partidas
    SELECT 
        player_id,
        AVG(duracion_seg) AS avg_jugador
    FROM duracion_por_juego
    GROUP BY player_id
),
jugadores_sobre_promedio AS (
    
    SELECT j.player_id
    FROM duracion_promedio_por_jugador j
    CROSS JOIN promedio_global p
    WHERE j.avg_jugador > p.avg_global
)
SELECT
    u.username,
    i.subscale,
    i.item_number, 
    i.text AS pregunta,
    ri.score AS puntaje
FROM jugadores_sobre_promedio jsp
JOIN "Player"       pl ON pl.player_id   = jsp.player_id
JOIN "User"         u  ON u.user_id      = pl.user_id
JOIN "Response"     r  ON r.user_id      = u.user_id
JOIN "ResponseItem" ri ON ri.response_id = r.response_id
JOIN "Item"         i  ON i.item_id      = ri.item_id
ORDER BY u.username, i.subscale, i.item_number;

-- QUERY 5: Sector más visitado (hotspot) por episodio y mapa

WITH celdas AS (
    SELECT
        g.episode,
        g.map                                       AS map_number,
        FLOOR(te.pos_x / 250.0) * 250               AS celda_x,
        FLOOR(te.pos_y / 250.0) * 250               AS celda_y,
        COUNT(*)                                    AS visitas
    FROM "TelemetryEvent" te
    JOIN "Game" g ON g.game_id = te.game_id
    GROUP BY g.episode, g.map, FLOOR(te.pos_x / 250.0) * 250, FLOOR(te.pos_y / 250.0) * 250
),
ranking AS (
    SELECT 
        episode,
        map_number,
        celda_x,
        celda_y,
        visitas,
        
        ROW_NUMBER() OVER (
            PARTITION BY episode, map_number
            ORDER BY visitas DESC, celda_x ASC, celda_y ASC
        ) AS rk
    FROM celdas
)
SELECT
    episode,
    map_number,
    celda_x,
    celda_y,
    visitas,
    CONCAT('[', celda_x, ' a ', celda_x + 250, ', ',
                celda_y, ' a ', celda_y + 250, ')') AS rango_coordenadas
FROM ranking
WHERE rk = 1
ORDER BY episode, map_number;
-- QUERY 7: Promedio de puntaje UX para jugadores con la trayectoria más corta por episodio

WITH posiciones_consecutivas AS (
    -- 1. Obtenemos las coordenadas del tic anterior para cada juego
    SELECT
        te.game_id, 
        te.pos_x, te.pos_y, te.pos_z,
        LAG(te.pos_x) OVER (PARTITION BY te.game_id ORDER BY te.tic) AS prev_x,
        LAG(te.pos_y) OVER (PARTITION BY te.game_id ORDER BY te.tic) AS prev_y,
        LAG(te.pos_z) OVER (PARTITION BY te.game_id ORDER BY te.tic) AS prev_z
    FROM "TelemetryEvent" te
),
distancia_por_juego AS (

    SELECT
        g.episode,
        g.player_id,
        g.game_id,
        SUM(SQRT(
            POWER(p.pos_x - p.prev_x, 2) +
            POWER(p.pos_y - p.prev_y, 2) +
            POWER(p.pos_z - p.prev_z, 2)
        )) AS distancia_total_juego
    FROM posiciones_consecutivas p
    JOIN "Game" g ON g.game_id = p.game_id
    WHERE p.prev_x IS NOT NULL
    GROUP BY g.episode, g.player_id, g.game_id
),
ranking_episodios AS (
    
    SELECT 
        episode,
        player_id,
        distancia_total_juego,
        ROW_NUMBER() OVER (
            PARTITION BY episode 
            ORDER BY distancia_total_juego ASC
        ) AS rk
    FROM distancia_por_juego
),
jugadores_minimos AS (
    
    SELECT episode, player_id
    FROM ranking_episodios
    WHERE rk = 1
)

SELECT
    jm.episode,
    u.username,
    i.subscale,
    ROUND(AVG(ri.score), 2) AS puntaje_promedio_ux
FROM jugadores_minimos jm
JOIN "Player"       pl ON pl.player_id   = jm.player_id
JOIN "User"         u  ON u.user_id      = pl.user_id
JOIN "Response"     r  ON r.user_id      = u.user_id
JOIN "ResponseItem" ri ON ri.response_id = r.response_id
JOIN "Item"         i  ON i.item_id      = ri.item_id
GROUP BY jm.episode, u.username, i.subscale
ORDER BY jm.episode, i.subscale;


-- QUERY 8: Distancia total y velocidad promedio por jugador en todas sus sesiones
WITH movimientos AS (
    SELECT
        g.player_id,
        te.game_id,
        te.tic,
        te.pos_x, te.pos_y, te.pos_z,
        LAG(te.pos_x) OVER (PARTITION BY te.game_id ORDER BY te.tic) AS prev_x,
        LAG(te.pos_y) OVER (PARTITION BY te.game_id ORDER BY te.tic) AS prev_y,
        LAG(te.pos_z) OVER (PARTITION BY te.game_id ORDER BY te.tic) AS prev_z
    FROM "TelemetryEvent" te
    JOIN "Game" g ON g.game_id = te.game_id
),
calculos AS (
    SELECT
        player_id,
        game_id,
        
        SUM(CASE 
            WHEN prev_x IS NOT NULL THEN 
                SQRT(POWER(pos_x - prev_x, 2) + POWER(pos_y - prev_y, 2) + POWER(pos_z - prev_z, 2))
            ELSE 0 
        END) AS distancia_total,
        
        MAX(tic) - MIN(tic) AS tics_totales
    FROM movimientos
    GROUP BY player_id, game_id
)
SELECT
    u.username,
    ROUND(SUM(c.distancia_total)::NUMERIC, 2)            AS distancia_total_unidades,
    SUM(c.tics_totales)                                  AS tics_totales,
    ROUND((SUM(c.tics_totales) / 35.0)::NUMERIC, 2)      AS duracion_total_seg,
    -- Velocidad promedio = Distancia Total / Tiempo Total en segundos
    ROUND(
        (SUM(c.distancia_total) / NULLIF(SUM(c.tics_totales) / 35.0, 0))::NUMERIC, 
        4
    ) AS velocidad_promedio_u_seg
FROM calculos c
JOIN "Player" p ON p.player_id = c.player_id
JOIN "User"   u ON u.user_id   = p.user_id
GROUP BY u.user_id, u.username
ORDER BY distancia_total_unidades DESC;

