-- Vistas y vista materializada

CREATE OR REPLACE VIEW vw_trayectoria_sesion AS
WITH movimientos AS (
    SELECT
        te.game_id,
        te.tic,
        te.pos_x, te.pos_y, te.pos_z,
        te.health, te.armor, te.ammo,
        te.event_type,
        LAG(te.pos_x) OVER (PARTITION BY te.game_id ORDER BY te.tic) AS prev_x,
        LAG(te.pos_y) OVER (PARTITION BY te.game_id ORDER BY te.tic) AS prev_y,
        LAG(te.pos_z) OVER (PARTITION BY te.game_id ORDER BY te.tic) AS prev_z
    FROM "TelemetryEvent" te
)
SELECT
    g.game_id,
    u.username,
    p.skill_level,
    g.difficulty,
    m.map_name,
    g.episode,
    g.map                                                AS map_number,
    MIN(mov.tic)                                         AS tic_inicio,
    MAX(mov.tic)                                         AS tic_fin,
    ROUND(((MAX(mov.tic) - MIN(mov.tic)) / 35.0)::NUMERIC, 2)
                                                         AS duracion_seg,
    ROUND(SUM(
        CASE WHEN mov.prev_x IS NOT NULL THEN
            SQRT(POWER(mov.pos_x - mov.prev_x, 2) +
                 POWER(mov.pos_y - mov.prev_y, 2) +
                 POWER(mov.pos_z - mov.prev_z, 2))
        ELSE 0 END
    )::NUMERIC, 2)                                       AS distancia_total,
    ROUND(AVG(mov.health)::NUMERIC, 1)                   AS salud_promedio,
    ROUND(AVG(mov.armor)::NUMERIC, 1)                    AS armadura_promedio,
    ROUND(AVG(mov.ammo)::NUMERIC, 1)                     AS municion_promedio,
    COUNT(*) FILTER (WHERE mov.event_type = 'combat')    AS eventos_combate,
    COUNT(*) FILTER (WHERE mov.event_type = 'movement')  AS eventos_movimiento,
    COUNT(*) FILTER (WHERE mov.event_type = 'interaction') AS eventos_interaccion
FROM movimientos mov
JOIN "Game"   g ON g.game_id   = mov.game_id
JOIN "Player" p ON p.player_id = g.player_id
JOIN "User"   u ON u.user_id   = p.user_id
JOIN "Map"    m ON m.episode   = g.episode AND m.map_number = g.map
GROUP BY g.game_id, u.username, p.skill_level,
         g.difficulty, m.map_name, g.episode, g.map;



-- VISTA 2: Estadísticas de movimiento por sector
-- Muestra cuánto tiempo pasó el jugador en cada sector, su salud promedio al entrar y el tipo de eventos ocurridos

CREATE OR REPLACE VIEW vw_movimiento_por_sector AS
SELECT
    g.episode,
    g.map                                               AS map_number,
    m.map_name,
    FLOOR(te.pos_x / 250.0) * 250                       AS celda_x,
    FLOOR(te.pos_y / 250.0) * 250                       AS celda_y,
    CONCAT(
        '(', (FLOOR(te.pos_x / 250.0) * 250)::INT,
        ' a ', (FLOOR(te.pos_x / 250.0) * 250 + 250)::INT,
        ', ', (FLOOR(te.pos_y / 250.0) * 250)::INT,
        ' a ', (FLOOR(te.pos_y / 250.0) * 250 + 250)::INT,
        ')'
    )                                                   AS rango_sector,
    u.username,
    COUNT(te.event_id)                                  AS total_eventos,
    
    ROUND(((MAX(te.tic) - MIN(te.tic)) / 35.0)::NUMERIC, 2) AS tiempo_seg,
    ROUND(AVG(te.health)::NUMERIC, 1)                   AS salud_promedio,
    ROUND(AVG(te.armor)::NUMERIC, 1)                    AS armadura_promedio,
    ROUND(AVG(te.ammo)::NUMERIC, 1)                     AS municion_promedio,
    COUNT(*) FILTER (WHERE te.event_type = 'combat')      AS combates,
    COUNT(*) FILTER (WHERE te.event_type = 'movement')    AS movimientos,
    COUNT(*) FILTER (WHERE te.event_type = 'interaction') AS interacciones,
    MIN(te.health)                                       AS salud_minima,
    MAX(te.health)                                       AS salud_maxima
FROM "TelemetryEvent" te
JOIN "Game"   g ON g.game_id   = te.game_id
JOIN "Player" p ON p.player_id = g.player_id
JOIN "User"   u ON u.user_id   = p.user_id
JOIN "Map"    m ON m.episode   = g.episode AND m.map_number = g.map
GROUP BY
    g.episode, g.map, m.map_name,
    FLOOR(te.pos_x / 250.0) * 250,
    FLOOR(te.pos_y / 250.0) * 250,
    u.username;

-- Vista Materializada:

CREATE MATERIALIZED VIEW IF NOT EXISTS mvw_hotspots AS
WITH celdas AS (
    SELECT
        g.episode,
        g.map                                   AS map_number,
        m.map_name,
        FLOOR(te.pos_x / 250.0) * 250           AS celda_x,
        FLOOR(te.pos_y / 250.0) * 250           AS celda_y,
        COUNT(*)                                AS visitas,
        ROUND(AVG(te.health)::NUMERIC, 1)       AS salud_promedio,
        ROUND(AVG(te.ammo)::NUMERIC, 1)         AS municion_promedio,
        COUNT(*) FILTER (WHERE te.event_type = 'combat') AS combates_en_celda
    FROM "TelemetryEvent" te
    JOIN "Game" g ON g.game_id   = te.game_id
    JOIN "Map"  m ON m.episode   = g.episode AND m.map_number = g.map
    GROUP BY
        g.episode, g.map, m.map_name,
        FLOOR(te.pos_x / 250.0) * 250,
        FLOOR(te.pos_y / 250.0) * 250
)
SELECT
    episode,
    map_number,
    map_name,
    celda_x,
    celda_y,
    CONCAT(
        '(', celda_x::INT, ' a ', (celda_x + 250)::INT,
        ', ', celda_y::INT, ' a ', (celda_y + 250)::INT,
        ')'
    ) AS rango,
    visitas,
    salud_promedio,
    municion_promedio,
    combates_en_celda,
    RANK() OVER (
        PARTITION BY episode, map_number
        ORDER BY visitas DESC
    ) AS ranking_popularidad
FROM celdas
ORDER BY episode, map_number, visitas DESC;


SELECT * FROM vw_trayectoria_sesion;
SELECT * FROM vw_movimiento_por_sector LIMIT 10;
SELECT * FROM mvw_hotspots WHERE ranking_popularidad <= 5;
